import 'package:bloc/bloc.dart';import 'package:firebase_auth/firebase_auth.dart';import 'package:flutter/cupertino.dart';part 'home_event.dart';part 'home_state.dart';class HomeBloc extends Bloc<HomeEvent, HomeState> {  final FirebaseAuth auth = FirebaseAuth.instance;  HomeBloc() : super(HomeInitial()) {    on<HomeEvent>((event, emit) {});    on<LogoutPressed>((event, emit) async {      try {        await auth.signOut();        emit(LogoutSuccess());      } catch (e) {        debugPrint(e.toString());      }    });  }}